// Validate the inbound x-n8n-api-key header
// In n8n webhook v2, headers are at $json.headers
const apiKey = $input.first().json.headers?.['x-n8n-api-key'] || '';
const expected = 'ucsxrW9pLioAS43nod5tP353faVOe'; // N8N_API_KEY from backend .env

if (!apiKey || apiKey !== expected) {
  return [{ json: { valid: false, error: 'Unauthorized' } }];
}

return [{ json: { valid: true } }];

// Build the organizations document from the webhook payload.
// In n8n webhook v2, the POST body is at $json.body
// Fall back to $json directly in case the structure differs.
const raw = $('Webhook').first().json;
const body = (raw.body && typeof raw.body === 'object' && raw.body.organizationIntentId)
  ? raw.body
  : raw;

const organizationIntentId = body.organizationIntentId;
const parentOrganizationId = body.parentOrganizationId;
const name = body.name || 'Unknown';
const businessPhoneNumber = body.businessPhoneNumber || null;
const allowExternalUser = body.allowExternalUser === true;
const userIntent = body.userIntent || null;
const intents = body.intents || [];

if (!organizationIntentId || !parentOrganizationId) {
  throw new Error('Missing required fields: organizationIntentId or parentOrganizationId. Received: ' + JSON.stringify(body));
}

// Strip lookupValue from parameters before storing
const cleanIntents = intents.map(intent => ({
  ...intent,
  parameters: (intent.parameters || []).map(({ lookupValue, ...rest }) => rest)
}));

// _id is stored as a plain string.
// n8n's MongoDB node returns _id as string, so WF3 saves organizationId as string,
// and WF4 queries with that same string — all consistent.
return [{
  json: {
    _id: organizationIntentId,
    parentOrganizationId,
    name,
    businessPhoneNumber,
    allowExternalUser,
    userIntent,
    intents: cleanIntents,
    updatedAt: new Date().toISOString()
  }
}];
